-- IMPORTAÇÃO FICHAS TÉCNICAS
-- Importa apenas produtos e ingredientes que existem em est_produtos
-- Não duplica fichas já existentes

-- ── (DRINK) CAIPIRINHA CAPRICHOSA - ESPECIAL
INSERT INTO est_fichas_tecnicas (produto_id, rendimento, unidade_rendimento, custo_total, custo_por_porcao, ativo)
SELECT ep.id, 1, 'porção', 0, 0, true
FROM est_produtos ep
WHERE UPPER(TRIM(ep.nome)) = UPPER('(DRINK) CAIPIRINHA CAPRICHOSA - ESPECIAL')
  AND NOT EXISTS (SELECT 1 FROM est_fichas_tecnicas ft WHERE ft.produto_id = ep.id AND ft.ativo = true);

INSERT INTO est_ficha_ingredientes (ficha_id, ingrediente_id, quantidade, unidade)
SELECT ft.id, ep_ing.id, 1.0, 'Litro'
FROM est_fichas_tecnicas ft
JOIN est_produtos ep_prod ON ft.produto_id = ep_prod.id
JOIN est_produtos ep_ing  ON UPPER(TRIM(ep_ing.nome)) = UPPER('MC ACESSORIO CAPRICHOSO')
WHERE UPPER(TRIM(ep_prod.nome)) = UPPER('(DRINK) CAIPIRINHA CAPRICHOSA - ESPECIAL')
  AND ft.ativo = true
  AND NOT EXISTS (
    SELECT 1 FROM est_ficha_ingredientes fi
    WHERE fi.ficha_id = ft.id AND fi.ingrediente_id = ep_ing.id
  );
INSERT INTO est_ficha_ingredientes (ficha_id, ingrediente_id, quantidade, unidade)
SELECT ft.id, ep_ing.id, 0.005, 'Kg'
FROM est_fichas_tecnicas ft
JOIN est_produtos ep_prod ON ft.produto_id = ep_prod.id
JOIN est_produtos ep_ing  ON UPPER(TRIM(ep_ing.nome)) = UPPER('MP CORANTE AZUL')
WHERE UPPER(TRIM(ep_prod.nome)) = UPPER('(DRINK) CAIPIRINHA CAPRICHOSA - ESPECIAL')
  AND ft.ativo = true
  AND NOT EXISTS (
    SELECT 1 FROM est_ficha_ingredientes fi
    WHERE fi.ficha_id = ft.id AND fi.ingrediente_id = ep_ing.id
  );
INSERT INTO est_ficha_ingredientes (ficha_id, ingrediente_id, quantidade, unidade)
SELECT ft.id, ep_ing.id, 0.08, 'Kg'
FROM est_fichas_tecnicas ft
JOIN est_produtos ep_prod ON ft.produto_id = ep_prod.id
JOIN est_produtos ep_ing  ON UPPER(TRIM(ep_ing.nome)) = UPPER('MP LIMÃO')
WHERE UPPER(TRIM(ep_prod.nome)) = UPPER('(DRINK) CAIPIRINHA CAPRICHOSA - ESPECIAL')
  AND ft.ativo = true
  AND NOT EXISTS (
    SELECT 1 FROM est_ficha_ingredientes fi
    WHERE fi.ficha_id = ft.id AND fi.ingrediente_id = ep_ing.id
  );
