FROM est_produtos ep
WHERE UPPER(TRIM(ep.nome)) = UPPER('(DRINK) RUBRO CORAÇÃO - TANQUERAY')
  AND NOT EXISTS (SELECT 1 FROM est_fichas_tecnicas ft WHERE ft.produto_id = ep.id AND ft.ativo = true);

INSERT INTO est_ficha_ingredientes (ficha_id, ingrediente_id, quantidade, unidade)
SELECT ft.id, ep_ing.id, 0.1, 'Kg'
FROM est_fichas_tecnicas ft
JOIN est_produtos ep_prod ON ft.produto_id = ep_prod.id
JOIN est_produtos ep_ing  ON UPPER(TRIM(ep_ing.nome)) = UPPER('MP PITAYA')
WHERE UPPER(TRIM(ep_prod.nome)) = UPPER('(DRINK) RUBRO CORAÇÃO - TANQUERAY')
  AND ft.ativo = true
  AND NOT EXISTS (
    SELECT 1 FROM est_ficha_ingredientes fi
    WHERE fi.ficha_id = ft.id AND fi.ingrediente_id = ep_ing.id
  );
