JOIN est_produtos ep_prod ON ft.produto_id = ep_prod.id
JOIN est_produtos ep_ing  ON UPPER(TRIM(ep_ing.nome)) = UPPER('MP LARANJA BAHIA')
WHERE UPPER(TRIM(ep_prod.nome)) = UPPER('APEROL SPRITZ')
  AND ft.ativo = true
  AND NOT EXISTS (
    SELECT 1 FROM est_ficha_ingredientes fi
    WHERE fi.ficha_id = ft.id AND fi.ingrediente_id = ep_ing.id
  );
