FROM est_fichas_tecnicas ft
JOIN est_produtos ep_prod ON ft.produto_id = ep_prod.id
JOIN est_produtos ep_ing  ON UPPER(TRIM(ep_ing.nome)) = UPPER('MP CREME DE LEITE FORNEAVEL')
